import React, { useState, useEffect, useCallback } from 'react';
import { walletAPI } from '../services/api';
import { useToast } from '../context/ToastContext';
import './Wallet.css';

export default function Wallet() {
  const toast = useToast();

  const [walletDetail, setWalletDetail] = useState(null);
  const [loading, setLoading]           = useState(true);

  // Add money form
  const [addAmount, setAddAmount]   = useState('');
  const [addDesc, setAddDesc]       = useState('');
  const [addLoading, setAddLoading] = useState(false);

  // Transfer form
  const [transferTo,     setTransferTo]     = useState('');
  const [transferAmount, setTransferAmount] = useState('');
  const [transferDesc,   setTransferDesc]   = useState('');
  const [transferLoading, setTransferLoading] = useState(false);

  // Active tab: 'add' | 'transfer'
  const [activeTab, setActiveTab] = useState('add');

  const fetchWallet = useCallback(async () => {
    setLoading(true);
    try {
      const res = await walletAPI.getMyWalletDetail();
      setWalletDetail(res.data);
    } catch {
      toast.error('Failed to load wallet');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchWallet(); }, [fetchWallet]);

  // ── Add Money ──────────────────────────────────────────────────────────────
  const handleAddMoney = async (e) => {
    e.preventDefault();
    const amount = parseFloat(addAmount);
    if (!amount || amount < 1) {
      toast.error('Enter a valid amount (min ₹1)');
      return;
    }
    setAddLoading(true);
    try {
      await walletAPI.addMoney({
        amount,
        description: addDesc.trim() || 'Added money to wallet',
      });
      toast.success(`₹${amount.toFixed(2)} added to wallet!`);
      setAddAmount('');
      setAddDesc('');
      fetchWallet();
    } catch (err) {
      toast.error(err.response?.data?.error || 'Failed to add money');
    } finally {
      setAddLoading(false);
    }
  };

  // ── Transfer Money ─────────────────────────────────────────────────────────
  const handleTransfer = async (e) => {
    e.preventDefault();
    const amount = parseFloat(transferAmount);
    const toId   = parseInt(transferTo);
    if (!toId || toId < 1) {
      toast.error('Enter a valid recipient user ID');
      return;
    }
    if (!amount || amount < 1) {
      toast.error('Enter a valid amount (min ₹1)');
      return;
    }
    setTransferLoading(true);
    try {
      await walletAPI.transferMoney({
        toUserId: toId,
        amount,
        description: transferDesc.trim() || undefined,
      });
      toast.success(`₹${amount.toFixed(2)} transferred successfully!`);
      setTransferTo('');
      setTransferAmount('');
      setTransferDesc('');
      fetchWallet();
    } catch (err) {
      toast.error(err.response?.data?.error || 'Transfer failed');
    } finally {
      setTransferLoading(false);
    }
  };

  // ── Quick top-up amounts ───────────────────────────────────────────────────
  const quickAmounts = [100, 250, 500, 1000, 2000, 5000];

  const formatDate = (dateStr) => {
    if (!dateStr) return '';
    return new Date(dateStr).toLocaleString('en-IN', {
      day: '2-digit', month: 'short', year: 'numeric',
      hour: '2-digit', minute: '2-digit',
    });
  };

  if (loading) {
    return (
      <div className="wallet-page">
        <div className="container">
          <div className="loading-wrap"><div className="spinner" /></div>
        </div>
      </div>
    );
  }

  const balance      = walletDetail?.balance ?? 0;
  const transactions = walletDetail?.transactions ?? [];

  return (
    <div className="wallet-page">
      <div className="container">

        {/* Page header */}
        <div className="wallet-header fade-up">
          <h1>💰 My Wallet</h1>
          <p className="text-dim">Manage your BookNest wallet balance</p>
        </div>

        <div className="wallet-grid">

          {/* ── Left column ─────────────────────────────────────── */}
          <div className="wallet-left">

            {/* Balance card */}
            <div className="balance-card fade-up">
              <div className="balance-label">Available Balance</div>
              <div className="balance-amount">₹{balance.toFixed(2)}</div>
              <div className="balance-sub">BookNest Wallet</div>
            </div>

            {/* Actions card */}
            <div className="card wallet-actions-card fade-up">

              {/* Tabs */}
              <div className="wallet-tabs">
                <button
                  className={`wallet-tab ${activeTab === 'add' ? 'active' : ''}`}
                  onClick={() => setActiveTab('add')}
                >
                  ➕ Add Money
                </button>
                <button
                  className={`wallet-tab ${activeTab === 'transfer' ? 'active' : ''}`}
                  onClick={() => setActiveTab('transfer')}
                >
                  ↗️ Transfer
                </button>
              </div>

              {/* Add Money form */}
              {activeTab === 'add' && (
                <form onSubmit={handleAddMoney} className="wallet-form">
                  <div className="quick-amounts">
                    {quickAmounts.map(amt => (
                      <button
                        type="button"
                        key={amt}
                        className={`quick-btn ${parseFloat(addAmount) === amt ? 'selected' : ''}`}
                        onClick={() => setAddAmount(String(amt))}
                      >
                        ₹{amt}
                      </button>
                    ))}
                  </div>

                  <div className="form-group">
                    <label>Amount (₹)</label>
                    <input
                      type="number"
                      min="1"
                      max="100000"
                      placeholder="Enter amount"
                      value={addAmount}
                      onChange={e => setAddAmount(e.target.value)}
                      required
                    />
                  </div>

                  <div className="form-group">
                    <label>Note (optional)</label>
                    <input
                      type="text"
                      placeholder="e.g. Added via UPI"
                      value={addDesc}
                      onChange={e => setAddDesc(e.target.value)}
                      maxLength={100}
                    />
                  </div>

                  <button
                    type="submit"
                    className="btn btn-gold btn-full"
                    disabled={addLoading}
                  >
                    {addLoading ? 'Adding…' : 'Add Money'}
                  </button>
                </form>
              )}

              {/* Transfer form */}
              {activeTab === 'transfer' && (
                <form onSubmit={handleTransfer} className="wallet-form">
                  <div className="form-group">
                    <label>Recipient User ID</label>
                    <input
                      type="number"
                      min="1"
                      placeholder="Enter user ID to send money"
                      value={transferTo}
                      onChange={e => setTransferTo(e.target.value)}
                      required
                    />
                  </div>

                  <div className="form-group">
                    <label>Amount (₹)</label>
                    <input
                      type="number"
                      min="1"
                      placeholder="Enter amount"
                      value={transferAmount}
                      onChange={e => setTransferAmount(e.target.value)}
                      required
                    />
                  </div>

                  <div className="form-group">
                    <label>Note (optional)</label>
                    <input
                      type="text"
                      placeholder="e.g. Sharing for book"
                      value={transferDesc}
                      onChange={e => setTransferDesc(e.target.value)}
                      maxLength={100}
                    />
                  </div>

                  <div className="transfer-warning">
                    ⚠️ Transfers cannot be reversed. Please verify the user ID.
                  </div>

                  <button
                    type="submit"
                    className="btn btn-gold btn-full"
                    disabled={transferLoading}
                  >
                    {transferLoading ? 'Sending…' : 'Transfer Money'}
                  </button>
                </form>
              )}
            </div>
          </div>

          {/* ── Right column — Transaction history ──────────────── */}
          <div className="wallet-right">
            <div className="card fade-up">
              <div className="txn-header">
                <h3>Transaction History</h3>
                <span className="text-dim text-sm">{transactions.length} transactions</span>
              </div>

              {transactions.length === 0 ? (
                <div className="empty-state">
                  <div className="icon">💸</div>
                  <h3>No transactions yet</h3>
                  <p>Add money to get started</p>
                </div>
              ) : (
                <div className="txn-list">
                  {transactions.map(tx => (
                    <div key={tx.transactionId} className={`txn-row ${tx.type.toLowerCase()}`}>
                      <div className="txn-icon">
                        {tx.type === 'CREDIT' ? '⬆️' : '⬇️'}
                      </div>
                      <div className="txn-info">
                        <div className="txn-desc">{tx.description}</div>
                        <div className="txn-date text-dim text-sm">{formatDate(tx.transactionDate)}</div>
                      </div>
                      <div className="txn-right">
                        <div className={`txn-amount ${tx.type === 'CREDIT' ? 'credit' : 'debit'}`}>
                          {tx.type === 'CREDIT' ? '+' : '-'}₹{tx.amount.toFixed(2)}
                        </div>
                        <div className="txn-balance text-dim text-sm">
                          Bal: ₹{tx.balanceAfter.toFixed(2)}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

        </div>
      </div>
    </div>
  );
}
